import { useEffect, useRef, useState } from "react";
import mapboxgl from "mapbox-gl";
import "mapbox-gl/dist/mapbox-gl.css";
import { Restaurant } from "@/hooks/useRestaurants";
import { calculateDistance } from "@/lib/geolocation";
import { useTranslation } from "react-i18next";
import { isIOSWebView } from "@/lib/externalLinks";
import { AlertTriangle, MapPin } from "lucide-react";
import { Button } from "@/components/ui/button";
import mapIcon from "@/assets/map-icon.png";

interface RestaurantMapProps {
  restaurants: Restaurant[];
  onRestaurantClick: (restaurant: Restaurant) => void;
  userLocation: { lat: number; lng: number } | null;
  radiusFilter: number | null;
  countryBbox?: [number, number, number, number] | null;
  onMapInit?: (map: mapboxgl.Map) => void;
  onMarkerClick?: (restaurant: Restaurant) => void;
  showViewDetailsButton?: boolean;
  fitBoundsMaxZoom?: number;
}

const SOURCE_ID = "restaurants-source";
const CLUSTER_LAYER = "clusters";
const CLUSTER_COUNT_LAYER = "cluster-count";
const CLUSTER_RING_LAYER = "cluster-ring";
const UNCLUSTERED_LAYER = "unclustered-point";
const MAP_ICON_ID = "restaurant-icon";

function buildGeoJSON(restaurants: Restaurant[]): GeoJSON.FeatureCollection {
  return {
    type: "FeatureCollection",
    features: restaurants.map((r) => ({
      type: "Feature" as const,
      geometry: { type: "Point" as const, coordinates: [r.lng, r.lat] },
      properties: {
        id: r.id,
        name: r.name,
        address: r.address,
        rating: r.rating ?? null,
        type: JSON.stringify(r.type ?? []),
      },
    })),
  };
}

/** Compute a stable fingerprint from restaurant IDs + filter params */
function computeDataKey(ids: string[], radiusFilter: number | null, countryBbox: any): string {
  return ids.sort().join(",") + `|${radiusFilter}|${JSON.stringify(countryBbox)}`;
}

const RestaurantMap = ({
  restaurants,
  onRestaurantClick,
  userLocation,
  radiusFilter,
  countryBbox,
  onMapInit,
  onMarkerClick,
  showViewDetailsButton = false,
  fitBoundsMaxZoom,
}: RestaurantMapProps) => {
  const { t } = useTranslation();
  const mapContainer = useRef<HTMLDivElement>(null);
  const map = useRef<mapboxgl.Map | null>(null);
  const popup = useRef<mapboxgl.Popup | null>(null);
  const [mapLoaded, setMapLoaded] = useState(false);
  const [mapError, setMapError] = useState<string | null>(null);
  const restaurantsRef = useRef<Restaurant[]>(restaurants);
  const lastDataKey = useRef<string>("");

  useEffect(() => { restaurantsRef.current = restaurants; }, [restaurants]);

  const onRestaurantClickRef = useRef(onRestaurantClick);
  const onMarkerClickRef = useRef(onMarkerClick);
  useEffect(() => {
    onRestaurantClickRef.current = onRestaurantClick;
    onMarkerClickRef.current = onMarkerClick;
  }, [onRestaurantClick, onMarkerClick]);

  // ── Map initialization ──
  useEffect(() => {
    if (!mapContainer.current || map.current) return;

    const token = import.meta.env.VITE_MAPBOX_TOKEN;
    if (!token) return;

    const checkWebGLSupport = (): boolean => {
      try {
        const canvas = document.createElement("canvas");
        const gl = canvas.getContext("webgl") || canvas.getContext("experimental-webgl");
        if (!gl) return false;
        return mapboxgl.supported();
      } catch { return false; }
    };

    if (!checkWebGLSupport()) {
      setMapError(t("map.webglNotSupported", "Your browser does not support map display"));
      return;
    }

    let retryCount = 0;
    const initMap = () => {
      if (!mapContainer.current) return;
      const rect = mapContainer.current.getBoundingClientRect();
      if (rect.width === 0 || rect.height === 0) {
        if (++retryCount >= 30) {
          if (isIOSWebView()) setMapError(t("map.loadError", "Map failed to load"));
          else setTimeout(initMap, 500);
          return;
        }
        setTimeout(initMap, 100);
        return;
      }

      try {
        mapboxgl.accessToken = token;
        const initialCenter: [number, number] = userLocation
          ? [userLocation.lng, userLocation.lat]
          : [-9.1393, 38.7223];

        map.current = new mapboxgl.Map({
          container: mapContainer.current,
          style: "mapbox://styles/mapbox/light-v11",
          center: initialCenter,
          zoom: 13,
          cooperativeGestures: true,
          doubleClickZoom: false,
          fadeDuration: isIOSWebView() ? 0 : 300,
          preserveDrawingBuffer: isIOSWebView(),
        });

        map.current.on("error", () => setMapError(t("map.loadError", "Map failed to load")));
        map.current.addControl(new mapboxgl.NavigationControl({ visualizePitch: true }), "top-right");

        map.current.on("load", () => {
          const m = map.current!;

          m.loadImage(mapIcon, (error, image) => {
            if (error || !image) return;
            if (!m.hasImage(MAP_ICON_ID)) m.addImage(MAP_ICON_ID, image, { sdf: false });

            m.addSource(SOURCE_ID, {
              type: "geojson",
              data: buildGeoJSON([]),
              cluster: true,
              clusterMaxZoom: 17,
              clusterRadius: 60,
            });

            // ── Cluster outer glow ring ──
            m.addLayer({
              id: CLUSTER_RING_LAYER,
              type: "circle",
              source: SOURCE_ID,
              filter: ["has", "point_count"],
              paint: {
                "circle-color": "hsla(174, 100%, 18%, 0.10)",
                "circle-radius": [
                  "step", ["get", "point_count"],
                  22,         // 2–9
                  10, 28,     // 10–49
                  50, 34,     // 50–99
                  100, 38,    // 100–499
                  500, 42,    // 500+
                ],
              },
            });

            // ── Cluster solid circle ──
            m.addLayer({
              id: CLUSTER_LAYER,
              type: "circle",
              source: SOURCE_ID,
              filter: ["has", "point_count"],
              paint: {
                "circle-color": [
                  "step", ["get", "point_count"],
                  "hsl(174, 80%, 28%)",    // 2–9: lighter, smaller groups
                  10, "hsl(174, 90%, 22%)", // 10–49
                  50, "hsl(174, 100%, 18%)",// 50–99: brand primary
                  100, "hsl(174, 100%, 14%)",// 100–499: darker
                  500, "hsl(174, 100%, 10%)",// 500+: darkest
                ],
                "circle-radius": [
                  "step", ["get", "point_count"],
                  14,         // 2–9
                  10, 18,     // 10–49
                  50, 22,     // 50–99
                  100, 26,    // 100–499
                  500, 30,    // 500+
                ],
                "circle-stroke-width": 2.5,
                "circle-stroke-color": "hsla(0, 0%, 100%, 0.9)",
                "circle-opacity": 0.95,
              },
            });

            // ── Cluster count text ──
            m.addLayer({
              id: CLUSTER_COUNT_LAYER,
              type: "symbol",
              source: SOURCE_ID,
              filter: ["has", "point_count"],
              layout: {
                "text-field": ["get", "point_count_abbreviated"],
                "text-font": ["DIN Offc Pro Bold", "Arial Unicode MS Bold"],
                "text-size": [
                  "step", ["get", "point_count"],
                  11,         // 2–9
                  10, 12,     // 10–49
                  50, 13,     // 50–99
                  100, 14,    // 100+
                ],
                "text-allow-overlap": true,
              },
              paint: { "text-color": "#ffffff" },
            });

            // ── Unclustered points (custom icon) ──
            m.addLayer({
              id: UNCLUSTERED_LAYER,
              type: "symbol",
              source: SOURCE_ID,
              filter: ["!", ["has", "point_count"]],
              layout: {
                "icon-image": MAP_ICON_ID,
                "icon-size": [
                  "interpolate", ["linear"], ["zoom"],
                  5, 0.18,
                  10, 0.25,
                  14, 0.30,
                  18, 0.36,
                ],
                "icon-allow-overlap": false,
                "icon-ignore-placement": false,
                "icon-anchor": "bottom",
                "icon-padding": 4,
                "symbol-sort-key": ["case", ["has", "rating"], ["-", 0, ["get", "rating"]], 999],
              },
            });

            // ── Interactions ──

            m.on("click", CLUSTER_LAYER, (e) => {
              const features = m.queryRenderedFeatures(e.point, { layers: [CLUSTER_LAYER] });
              if (!features.length) return;
              const clusterId = features[0].properties!.cluster_id;
              const source = m.getSource(SOURCE_ID) as mapboxgl.GeoJSONSource;
              source.getClusterExpansionZoom(clusterId, (err, zoom) => {
                if (err) return;
                const geom = features[0].geometry as GeoJSON.Point;
                m.easeTo({
                  center: geom.coordinates as [number, number],
                  zoom: zoom ?? 15,
                  duration: 500,
                });
              });
            });

            m.on("click", UNCLUSTERED_LAYER, (e) => {
              const features = m.queryRenderedFeatures(e.point, { layers: [UNCLUSTERED_LAYER] });
              if (!features.length) return;
              const props = features[0].properties!;
              const geom = features[0].geometry as GeoJSON.Point;
              const coords = geom.coordinates as [number, number];
              const restaurant = restaurantsRef.current.find((r) => r.id === props.id);
              if (!restaurant) return;

              const types: string[] = JSON.parse(props.type || "[]");
              const popupHTML = `
                <div class="restaurant-popup">
                  <h3 class="restaurant-popup__name">${props.name}</h3>
                  ${types.length > 0 ? `
                    <div class="restaurant-popup__tags">
                      ${types.slice(0, 2).map((ty: string) =>
                        `<span class="restaurant-popup__tag">${ty}</span>`
                      ).join("")}
                    </div>` : ""}
                  ${props.rating ? `
                    <div class="restaurant-popup__rating">
                      <span class="restaurant-popup__star">★</span>
                      <span class="restaurant-popup__rating-value">${Number(props.rating).toFixed(1)}</span>
                    </div>` : ""}
                  <p class="restaurant-popup__address">${props.address}</p>
                  ${showViewDetailsButton ? `
                    <button id="popup-details-btn" class="restaurant-popup__btn">
                      ${t("restaurants.viewDetails")}
                    </button>` : ""}
                </div>
              `;

              if (popup.current) popup.current.remove();

              popup.current = new mapboxgl.Popup({
                offset: 25,
                closeButton: true,
                closeOnClick: false,
                closeOnMove: false,
                maxWidth: "300px",
                className: "restaurant-map-popup",
              })
                .setLngLat(coords)
                .setHTML(popupHTML)
                .addTo(m);

              if (showViewDetailsButton) {
                popup.current.on("open", () => {
                  const btn = document.getElementById("popup-details-btn");
                  btn?.addEventListener("click", (ev) => {
                    ev.stopPropagation();
                    onRestaurantClickRef.current(restaurant);
                  });
                });
              }

              m.easeTo({ center: coords, zoom: Math.max(m.getZoom(), 15), duration: 800 });

              if (onMarkerClickRef.current) onMarkerClickRef.current(restaurant);
            });

            m.on("mouseenter", CLUSTER_LAYER, () => { m.getCanvas().style.cursor = "pointer"; });
            m.on("mouseleave", CLUSTER_LAYER, () => { m.getCanvas().style.cursor = ""; });
            m.on("mouseenter", UNCLUSTERED_LAYER, () => { m.getCanvas().style.cursor = "pointer"; });
            m.on("mouseleave", UNCLUSTERED_LAYER, () => { m.getCanvas().style.cursor = ""; });

            setMapLoaded(true);
            if (onMapInit) onMapInit(m);
          });
        });
      } catch {
        setMapError(t("map.loadError", "Map failed to load"));
      }
    };

    isIOSWebView() ? setTimeout(initMap, 200) : initMap();

    // ResizeObserver to handle container size changes (lazy loading, Suspense, etc.)
    const container = mapContainer.current;
    const resizeObserver = new ResizeObserver(() => {
      if (map.current) {
        map.current.resize();
      }
    });
    if (container) resizeObserver.observe(container);

    return () => {
      resizeObserver.disconnect();
      popup.current?.remove();
      popup.current = null;
      map.current?.remove();
      map.current = null;
      setMapLoaded(false);
    };
  }, []);

  // ── Update GeoJSON data — only fitBounds when data actually changes ──
  useEffect(() => {
    if (!map.current || !mapLoaded) return;
    const source = map.current.getSource(SOURCE_ID) as mapboxgl.GeoJSONSource | undefined;
    if (!source) return;

    let filtered = restaurants;
    if (userLocation && radiusFilter) {
      filtered = restaurants.filter((r) =>
        calculateDistance(userLocation.lat, userLocation.lng, r.lat, r.lng) <= radiusFilter
      );
    }

    // Always update the data (cheap O(1) call)
    source.setData(buildGeoJSON(filtered));

    // Only fitBounds when the actual dataset or filter params change
    const newKey = computeDataKey(filtered.map((r) => r.id), radiusFilter, countryBbox);
    if (newKey === lastDataKey.current) return; // data didn't change — don't move the map
    lastDataKey.current = newKey;

    // Close popup on real data change
    if (popup.current) { popup.current.remove(); popup.current = null; }

    if (filtered.length > 0) {
      if (userLocation && !radiusFilter && countryBbox) {
        map.current.fitBounds(
          [[countryBbox[0], countryBbox[1]], [countryBbox[2], countryBbox[3]]],
          { padding: 30, maxZoom: 8 }
        );
      } else if (userLocation && radiusFilter) {
        const bounds = new mapboxgl.LngLatBounds();
        filtered.forEach((r) => bounds.extend([r.lng, r.lat]));
        bounds.extend([userLocation.lng, userLocation.lat]);
        map.current.fitBounds(bounds, { padding: 50, maxZoom: 15 });
      } else if (!userLocation) {
        const bounds = new mapboxgl.LngLatBounds();
        filtered.forEach((r) => bounds.extend([r.lng, r.lat]));
        map.current.fitBounds(bounds, { padding: 50, maxZoom: fitBoundsMaxZoom ?? 15 });
      }
    }
  }, [restaurants, radiusFilter, userLocation, mapLoaded, countryBbox, fitBoundsMaxZoom]);

  // ── Fly to user location — only when radiusFilter is set (not country view) ──
  useEffect(() => {
    if (map.current && userLocation && mapLoaded && radiusFilter) {
      map.current.flyTo({ center: [userLocation.lng, userLocation.lat], zoom: 14, duration: 1500 });
    }
  }, [userLocation, mapLoaded, radiusFilter]);

  // ── User location blue dot ──
  useEffect(() => {
    if (!map.current || !userLocation || !mapLoaded) return;
    const el = document.createElement("div");
    el.className = "user-location-pulse";
    const userMarker = new mapboxgl.Marker(el)
      .setLngLat([userLocation.lng, userLocation.lat])
      .addTo(map.current);
    return () => { userMarker.remove(); };
  }, [userLocation, mapLoaded]);

  if (mapError) {
    return (
      <div className="w-full h-full rounded-lg overflow-hidden bg-muted/50 flex flex-col items-center justify-center p-6 text-center">
        <AlertTriangle className="w-12 h-12 text-muted-foreground mb-4" />
        <p className="text-muted-foreground mb-2">{mapError}</p>
        <p className="text-sm text-muted-foreground mb-4">
          {t("map.viewListInstead", "Please view the restaurant list below")}
        </p>
        {isIOSWebView() && (
          <Button variant="outline" size="sm" onClick={() => window.open(window.location.href, "_blank")}>
            <MapPin className="w-4 h-4 mr-2" />
            {t("map.openInBrowser", "Open in Browser")}
          </Button>
        )}
      </div>
    );
  }

  return (
    <div
      ref={mapContainer}
      className="w-full h-full rounded-lg overflow-hidden"
      style={{ minHeight: "300px", WebkitTransform: "translateZ(0)" }}
    />
  );
};

export default RestaurantMap;
